<?php
require_once __DIR__.'/../config.php';require_once __DIR__.'/../lib/layout.php';require_once __DIR__.'/../lib/identidad_lifecycle.php';requiere_roles(['ADMIN','TI','RRHH','DIRECTOR','GERENCIA','CEO'],'../');$pdo=db();$actor=usuario_actual();$id=(int)($_GET['id']??$_POST['ciclo_id']??0);$ciclo=ciclo_identidad_obtener($pdo,$id);if(!$ciclo){http_response_code(404);exit('Ciclo no encontrado.');}$msg=isset($_GET['creado'])?['ok','Plan de tareas creado. Revisa y aprueba antes de ejecutar.']:null;
if($_SERVER['REQUEST_METHOD']==='POST'){try{$a=$_POST['accion']??'';if($a==='aprobar')$ciclo=ciclo_identidad_aprobar($pdo,$id,$actor);elseif($a==='completar_manual')ciclo_identidad_completar_manual($pdo,(int)$_POST['tarea_id'],(string)($_POST['evidencia']??''),$actor);elseif($a==='ejecutar_auto'){if(!tiene_rol(['ADMIN','TI']))throw new RuntimeException('Solo TI puede ejecutar acciones automáticas.');ciclo_identidad_ejecutar_automatica($pdo,(int)$_POST['tarea_id'],$actor,(string)($_POST['confirmacion_correo']??''));}$ciclo=ciclo_identidad_obtener($pdo,$id);$msg=['ok','Ciclo actualizado correctamente.'];}catch(Throwable $e){$msg=['error',$e->getMessage()];}}
$tareas=ciclo_identidad_tareas($pdo,$id);layout_inicio($ciclo['codigo'],'Ciclo de identidad','../');?>
<div class="page-kicker">IDENTIDAD · <?=$ciclo['tipo']?></div><h1><?=icon('users','icon-lg')?> <?=e($ciclo['codigo'])?></h1><p class="subtitle"><?=e($ciclo['empleado_nombre'])?> · <?=e($ciclo['correo_corporativo'])?></p><?php if($msg):?><div class="msg-<?=e($msg[0])?>"><?=e($msg[1])?></div><?php endif;?>
<div class="cycle-summary"><div><span>Estado</span><strong><?=e($ciclo['estado'])?></strong></div><div><span>Progreso</span><strong><?=(int)$ciclo['progreso']?>%</strong></div><div><span>Fecha efectiva</span><strong><?=e($ciclo['fecha_efectiva']?:'Sin definir')?></strong></div><div><span>Área destino</span><strong><?=e($ciclo['area_destino']?:'No aplica')?></strong></div></div>
<?php if($ciclo['estado']==='PENDIENTE'&&tiene_rol(['ADMIN','RRHH'])):?><form method="post" class="panel approval-callout"><input type="hidden" name="accion" value="aprobar"><input type="hidden" name="ciclo_id" value="<?=$id?>"><div><span class="page-kicker">CONTROL PREVIO</span><h3>Aprobar plan de ejecución</h3><p>La aprobación habilita las tareas, pero ninguna acción externa se ejecuta automáticamente.</p></div><button><?=icon('check')?> Aprobar ciclo</button></form><?php endif;?>
<section class="panel"><h3>Plan de ejecución</h3><div class="lifecycle-list"><?php foreach($tareas as $i=>$t):$disponible=ciclo_tarea_disponible($pdo,$t);?><article class="lifecycle-task <?=$t['estado']==='COMPLETADA'?'done':($t['estado']==='ERROR'?'failed':'')?>"><div class="task-index"><?=str_pad((string)($i+1),2,'0',STR_PAD_LEFT)?></div><div class="task-body"><div class="task-meta"><span><?=e($t['sistema'])?></span><span><?=e($t['area_responsable'])?></span><span class="badge <?=$t['modo']==='AUTO_GRAPH'?'badge-err':($t['modo']==='AUTO_LOCAL'?'badge-warn':'badge-otro')?>"><?=e($t['modo'])?></span></div><h3><?=e($t['titulo'])?></h3><?php if($t['evidencia']):?><p class="task-evidence"><?=e($t['evidencia'])?> · <?=e($t['ejecutado_por'])?></p><?php endif;?><?php if($t['ultimo_error']):?><p class="msg-error"><?=e($t['ultimo_error'])?></p><?php endif;?></div><div class="task-action"><?php if($t['estado']==='COMPLETADA'):?><span class="badge badge-activo">COMPLETADA</span><?php elseif(!in_array($ciclo['estado'],['APROBADO','EN_EJECUCION'],true)):?><span class="small">Esperando aprobación</span><?php elseif(!$disponible):?><span class="small">Bloqueada por secuencia</span><?php elseif($t['modo']==='MANUAL'):?><form method="post"><input type="hidden" name="accion" value="completar_manual"><input type="hidden" name="ciclo_id" value="<?=$id?>"><input type="hidden" name="tarea_id" value="<?=(int)$t['id']?>"><input name="evidencia" required placeholder="Evidencia breve"><button>Completar</button></form><?php elseif(tiene_rol(['ADMIN','TI'])):?><form method="post" onsubmit="return confirm('<?= $t['modo']==='AUTO_GRAPH'?'Esta acción modificará la cuenta real en Microsoft 365. ¿Confirmas?':'¿Ejecutar esta acción local verificada?'?>')"><input type="hidden" name="accion" value="ejecutar_auto"><input type="hidden" name="ciclo_id" value="<?=$id?>"><input type="hidden" name="tarea_id" value="<?=(int)$t['id']?>"><?php if($t['modo']==='AUTO_GRAPH'):?><label class="small">Escribe <?=e($ciclo['correo_corporativo'])?></label><input type="email" name="confirmacion_correo" required autocomplete="off" placeholder="Correo exacto"><?php endif;?><button class="<?=$t['modo']==='AUTO_GRAPH'?'btn-danger':''?>"><?=$t['modo']==='AUTO_GRAPH'?'Ejecutar en Microsoft':'Ejecutar'?></button></form><?php endif;?></div></article><?php endforeach;?></div></section>
<div class="toolbar"><?php if($ciclo['solicitud_id']):?><a class="btn btn-secondary" href="solicitud_detalle.php?id=<?=(int)$ciclo['solicitud_id']?>">Ver <?=e($ciclo['solicitud_codigo'])?></a><?php endif;?><a class="btn btn-secondary" href="identidades.php">Volver a identidades</a></div><?php layout_fin();?>
